const HIDDEN_UNION_TERRITORIES = new Set([
  "Chandigarh",
  "Dadra and Nagar Haveli and Daman and Diu",
  "Puducherry",
]);

MAP_DATA.states = MAP_DATA.states.filter(
  ({ name }) => !HIDDEN_UNION_TERRITORIES.has(name),
);
MAP_DATA.compactTerritories = MAP_DATA.compactTerritories.filter(
  ({ name }) => !HIDDEN_UNION_TERRITORIES.has(name),
);
HIDDEN_UNION_TERRITORIES.forEach((name) => delete MAP_DATA.places[name]);

import travelStories from "./travelStories.js";

export const [VIEW_W, VIEW_H] = MAP_DATA.viewBox;

const LEGACY_VISITED_PLACES = {
  Jharkhand: ["Jamshedpur"],
  "Uttar Pradesh": ["Lucknow", "Varanasi Ghats"],
  Bihar: ["Patna", "Nalanda"],
  "Jammu and Kashmir": [
    "Srinagar",
    "Gulmarg",
    "Pahalgam",
    "Sonamarg",
    "Dal Lake, Srinagar",
  ],
  "Himachal Pradesh": ["Jalori Pass"],
};

const normalizeLocationName = (value = "") =>
  value
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, " ")
    .trim();

const stateNames = [...MAP_DATA.states.map(({ name }) => name), "Lakshadweep"];
const stateNameByNormalizedName = new Map(
  stateNames.map((name) => [normalizeLocationName(name), name]),
);
const stateAliases = new Map([
  ["kashmir", "Jammu and Kashmir"],
  ["jammu kashmir", "Jammu and Kashmir"],
  ["andaman nicobar", "Andaman and Nicobar"],
  ["andaman and nicobar islands", "Andaman and Nicobar"],
  ["orissa", "Odisha"],
]);

const resolveMapStateName = (story) => {
  const normalizedState = normalizeLocationName(story.state);
  const directMatch =
    stateAliases.get(normalizedState) ||
    stateNameByNormalizedName.get(normalizedState);
  if (directMatch) return directMatch;

  const normalizedLocation = normalizeLocationName(story.location);
  return stateNames.find((name) =>
    normalizedLocation.includes(normalizeLocationName(name)),
  );
};

const findMatchingPlace = (places, place) => {
  const normalizedPlace = normalizeLocationName(place);
  return places.find((existingPlace) => {
    const normalizedExistingPlace = normalizeLocationName(existingPlace);
    return (
      normalizedExistingPlace === normalizedPlace ||
      normalizedExistingPlace.startsWith(`${normalizedPlace} `) ||
      normalizedPlace.startsWith(`${normalizedExistingPlace} `)
    );
  });
};

const storyVisits = travelStories.reduce((visits, story) => {
  const stateName = resolveMapStateName(story);
  if (!stateName) return visits;

  const destination = story.location?.split(",")[0]?.trim();
  const storyPlaces = [destination].filter(Boolean);
  const availablePlaces = MAP_DATA.places[stateName] || [];
  MAP_DATA.places[stateName] = availablePlaces;

  if (!visits[stateName]) visits[stateName] = [];
  storyPlaces.forEach((place) => {
    const matchingPlace = findMatchingPlace(availablePlaces, place);
    const mapPlace = matchingPlace || place;
    if (!matchingPlace) availablePlaces.push(place);
    if (!findMatchingPlace(visits[stateName], mapPlace)) {
      visits[stateName].push(mapPlace);
    }
  });

  return visits;
}, {});

export const VISITED_PLACES = Object.entries({
  ...LEGACY_VISITED_PLACES,
  ...storyVisits,
}).reduce((allVisits, [stateName]) => {
  allVisits[stateName] = [
    ...(LEGACY_VISITED_PLACES[stateName] || []),
    ...(storyVisits[stateName] || []),
  ].filter(
    (place, index, allPlaces) =>
      allPlaces.findIndex(
        (candidate) =>
          normalizeLocationName(candidate) === normalizeLocationName(place),
      ) === index,
  );
  return allVisits;
}, {});

export const VISITED_STATES = new Set(Object.keys(VISITED_PLACES));

const UNION_TERRITORIES = new Set([
  "Andaman and Nicobar",
  "Chandigarh",
  "Dadra and Nagar Haveli and Daman and Diu",
  "Delhi",
  "Jammu and Kashmir",
  "Ladakh",
  "Lakshadweep",
  "Puducherry",
]);

const visitedRegions = Object.entries(VISITED_PLACES).filter(
  ([, places]) => places.length > 0,
);

export const JOURNEY_STATS = {
  totalStates: 28,
  totalUnionTerritories: 8,
  visitedStates: visitedRegions.filter(
    ([regionName]) => !UNION_TERRITORIES.has(regionName),
  ).length,
  visitedUnionTerritories: visitedRegions.filter(([regionName]) =>
    UNION_TERRITORIES.has(regionName),
  ).length,
  visitedCities: visitedRegions.reduce(
    (total, [, places]) => total + places.length,
    0,
  ),
};

